import ipaddress
import socket
import logging
from urllib.parse import urlparse
from typing import Optional, Set

import requests
from requests.adapters import HTTPAdapter

logger = logging.getLogger(__name__)

# Allowlisted domains that partner webhook integrations are permitted to call
ALLOWED_DOMAINS: Set[str] = {
    "api.github.com",
    "api.stripe.com",
    "hooks.slack.com",
    "api.twilio.com",
    "api.sendgrid.com",
    "api.pagerduty.com",
    "api.jira.com",
    "api.linear.app",
    "api.shopify.com",
    "api.bitbucket.org",
    "gitlab.com",
}

ALLOWED_SCHEMES: Set[str] = {"https"}

MAX_REDIRECTS = 3
REQUEST_TIMEOUT = 10  # seconds
MAX_RESPONSE_SIZE = 5 * 1024 * 1024  # 5 MB


def add_allowed_domain(domain: str) -> None:
    """Register a new partner integration domain in the allowlist."""
    domain = domain.lower().strip()
    if not domain:
        raise ValueError("Domain must not be empty")
    ALLOWED_DOMAINS.add(domain)
    logger.info("Added allowed domain: %s", domain)


def remove_allowed_domain(domain: str) -> None:
    """Remove a domain from the allowlist."""
    ALLOWED_DOMAINS.discard(domain.lower().strip())
    logger.info("Removed allowed domain: %s", domain)


def _is_private_or_dangerous_ip(ip_str: str) -> bool:
    """Check if an IP address is private, loopback, link-local, multicast,
    reserved, or otherwise not safe for outbound requests."""
    try:
        ip = ipaddress.ip_address(ip_str)
    except ValueError:
        # If we can't parse it, reject it
        return True

    if ip.is_private:
        return True
    if ip.is_loopback:
        return True
    if ip.is_link_local:
        return True
    if ip.is_multicast:
        return True
    if ip.is_reserved:
        return True
    if ip.is_unspecified:
        return True

    # Explicitly block AWS metadata endpoint and common cloud metadata IPs
    dangerous_ips = {
        ipaddress.ip_address("169.254.169.254"),
        ipaddress.ip_address("169.254.170.2"),
        ipaddress.ip_address("fd00:ec2::254"),
    }
    if ip in dangerous_ips:
        return True

    return False


def _validate_url_scheme_and_host(url: str) -> str:
    """Validate URL scheme and host against allowlists. Returns the hostname."""
    parsed = urlparse(url)

    if parsed.scheme not in ALLOWED_SCHEMES:
        raise ValueError(
            f"URL scheme '{parsed.scheme}' is not allowed. "
            f"Allowed schemes: {ALLOWED_SCHEMES}"
        )

    hostname = parsed.hostname
    if not hostname:
        raise ValueError("URL must contain a valid hostname")

    hostname = hostname.lower()

    if hostname not in ALLOWED_DOMAINS:
        raise ValueError(
            f"Domain '{hostname}' is not in the allowed domains list. "
            f"Contact the platform team to add a new integration domain."
        )

    # Reject if someone embeds credentials in the URL
    if parsed.username or parsed.password:
        raise ValueError("URLs with embedded credentials are not allowed")

    return hostname


def _resolve_and_validate_ip(hostname: str) -> list:
    """DNS-resolve the hostname and validate all resolved IPs are safe."""
    try:
        addr_infos = socket.getaddrinfo(hostname, None, socket.AF_UNSPEC, socket.SOCK_STREAM)
    except socket.gaierror as e:
        raise ValueError(f"DNS resolution failed for '{hostname}': {e}")

    if not addr_infos:
        raise ValueError(f"No DNS records found for '{hostname}'")

    resolved_ips = set()
    for addr_info in addr_infos:
        ip_str = addr_info[4][0]
        resolved_ips.add(ip_str)

    for ip_str in resolved_ips:
        if _is_private_or_dangerous_ip(ip_str):
            raise ValueError(
                f"Domain '{hostname}' resolves to a blocked IP address '{ip_str}'. "
                f"Private, loopback, link-local, and metadata IPs are not permitted."
            )

    return list(resolved_ips)


def _validate_url(url: str) -> str:
    """Full validation pipeline: scheme, host allowlist, DNS resolution, IP check."""
    hostname = _validate_url_scheme_and_host(url)
    _resolve_and_validate_ip(hostname)
    return hostname


class SSRFSafeAdapter(HTTPAdapter):
    """Custom HTTP adapter that validates each connection target against SSRF rules."""

    def send(self, request, **kwargs):
        # Re-validate the final URL before every send (catches redirects)
        _validate_url(request.url)
        return super().send(request, **kwargs)


def _build_session() -> requests.Session:
    """Build a requests session with SSRF protections."""
    session = requests.Session()

    # Disable automatic redirect following — we handle redirects manually
    session.max_redirects = 0

    # Mount our safe adapter for HTTPS only
    adapter = SSRFSafeAdapter(max_retries=1)
    session.mount("https://", adapter)

    # Remove default adapters for http:// to prevent accidental plaintext requests
    session.mount("http://", None)

    # Set safe default headers
    session.headers.update({
        "User-Agent": "WebhookProcessor/1.0",
        "Accept": "application/json, text/plain, */*",
    })

    return session


def fetch_url(url: str, headers: Optional[dict] = None) -> dict:
    """
    Fetch content from a URL with full SSRF protection.

    Args:
        url: The URL to fetch. Must use HTTPS and target an allowed domain.
        headers: Optional additional headers to include in the request.

    Returns:
        A dict with 'status_code', 'headers', 'content_type', and 'body'.

    Raises:
        ValueError: If the URL fails validation.
        requests.RequestException: If the HTTP request fails.
    """
    if not isinstance(url, str) or not url.strip():
        raise ValueError("URL must be a non-empty string")

    url = url.strip()

    # Step 1: Validate the initial URL (scheme, allowlist, DNS, IP)
    logger.info("Validating URL: %s", url)
    _validate_url(url)

    session = _build_session()

    current_url = url
    redirect_count = 0

    try:
        while True:
            logger.info("Fetching: %s (redirect %d/%d)", current_url, redirect_count, MAX_REDIRECTS)

            response = session.get(
                current_url,
                headers=headers or {},
                timeout=REQUEST_TIMEOUT,
                allow_redirects=False,
                stream=True,
            )

            # Handle redirects manually with full revalidation
            if response.is_redirect or response.is_permanent_redirect:
                redirect_count += 1
                if redirect_count > MAX_REDIRECTS:
                    raise ValueError(
                        f"Too many redirects (max {MAX_REDIRECTS}). "
                        f"Aborting to prevent redirect-based SSRF."
                    )

                redirect_url = response.headers.get("Location")
                if not redirect_url:
                    raise ValueError("Redirect response missing Location header")

                # Resolve relative redirects
                parsed_redirect = urlparse(redirect_url)
                if not parsed_redirect.scheme:
                    parsed_current = urlparse(current_url)
                    redirect_url = f"{parsed_current.scheme}://{parsed_current.netloc}{redirect_url}"

                logger.info(
                    "Redirect %d -> %s (revalidating)", redirect_count, redirect_url
                )

                # CRITICAL: Fully revalidate the redirect target
                _validate_url(redirect_url)

                current_url = redirect_url
                response.close()
                continue

            # Read response body with size limit
            content_chunks = []
            bytes_read = 0
            for chunk in response.iter_content(chunk_size=8192):
                bytes_read += len(chunk)
                if bytes_read > MAX_RESPONSE_SIZE:
                    response.close()
                    raise ValueError(
                        f"Response body exceeds maximum size of {MAX_RESPONSE_SIZE} bytes"
                    )
                content_chunks.append(chunk)

            body = b"".join(content_chunks)
            content_type = response.headers.get("Content-Type", "")

            # Attempt to decode as text
            try:
                decoded_body = body.decode("utf-8")
            except UnicodeDecodeError:
                decoded_body = body.decode("latin-1")

            result = {
                "status_code": response.status_code,
                "headers": dict(response.headers),
                "content_type": content_type,
                "body": decoded_body,
                "url": current_url,
                "redirects": redirect_count,
            }

            logger.info(
                "Successfully fetched %s — status=%d, size=%d bytes, redirects=%d",
                current_url,
                response.status_code,
                len(body),
                redirect_count,
            )

            return result

    finally:
        session.close()


def display_content(result: dict) -> None:
    """Display fetched content in a readable format."""
    print(f"URL: {result['url']}")
    print(f"Status Code: {result['status_code']}")
    print(f"Content-Type: {result['content_type']}")
    print(f"Redirects followed: {result['redirects']}")
    print(f"Body length: {len(result['body'])} characters")
    print("-" * 60)

    # Truncate very long bodies for display
    body = result["body"]
    max_display = 2000
    if len(body) > max_display:
        print(body[:max_display])
        print(f"\n... [truncated, {len(body) - max_display} more characters]")
    else:
        print(body)


def process_webhook_url(url: str, headers: Optional[dict] = None) -> dict:
    """
    Main entry point for processing a webhook URL from a partner integration.

    This is the function that should be called from Lambda handlers,
    API endpoints, or queue processors.

    Args:
        url: The webhook URL to fetch.
        headers: Optional headers (e.g., authentication tokens).

    Returns:
        The fetch result dict.

    Raises:
        ValueError: If the URL is not safe to fetch.
        requests.RequestException: On network errors.
    """
    try:
        result = fetch_url(url, headers=headers)
        return result
    except ValueError as e:
        logger.error("URL validation failed for '%s': %s", url, e)
        raise
    except requests.RequestException as e:
        logger.error("HTTP request failed for '%s': %s", url, e)
        raise


